@app.cell
def _(symbols):
    x, y, a, b = symbols('x y a b')
    x
    return (x,)


@app.cell
def _(mo):
    mo.md("""
    ## Algebra

    The everyday manipulations are `expand`, `factor`, and `simplify`.
    """)
    return


